window.PNM_FONT_REG="";
window.PNM_FONT_BOLD="";

/* ===== PoródNaMiarę.pl — generator PDF planu porodu (jsPDF) ===== */
(function(){
  'use strict';
  var W=210, H=297;

  function theme(g){
    return g==='boy'
      ? {ac:[62,126,118], soft:[228,242,240]}
      : {ac:[160,82,94],  soft:[247,233,231]};
  }
  var DEEP=[62,56,82], INK=[58,51,65], SAND=[250,245,239], SD=[237,223,211], GREY=[138,131,145];

  function heart(d,x,y,s,col){
    d.setFillColor(col[0],col[1],col[2]);
    d.lines([[-s,-0.75*s,-s,-1.6*s,0,-1.15*s],[s,-0.45*s,s,0.6*s,0,1.15*s]], x, y+0.55*s, [1,1], 'F', true);
  }

  function Doc(g){
    var t=theme(g);
    var d=new window.jspdf.jsPDF({unit:'mm',format:'a4',compress:true});
    d.addFileToVFS('Lato-R.ttf', window.PNM_FONT_REG);
    d.addFont('Lato-R.ttf','Lato','normal');
    d.addFileToVFS('Lato-B.ttf', window.PNM_FONT_BOLD);
    d.addFont('Lato-B.ttf','Lato','bold');
    d.setFont('Lato','normal');
    return {d:d, t:t, page:0, y:0};
  }

  function cover(c, dziecko, rodzice, termin){
    var d=c.d, t=c.t; c.page=1;
    d.setFillColor(t.soft[0],t.soft[1],t.soft[2]); d.rect(0,0,W,H,'F');
    d.setFillColor(t.ac[0],t.ac[1],t.ac[2]); d.rect(0,0,W,110,'F');
    heart(d, W/2, 32, 7, [255,255,255]);
    d.setTextColor(255,255,255);
    d.setFont('Lato','bold'); d.setFontSize(10);
    d.text('PLAN PORODU', W/2, 62, {align:'center', charSpace:1.2});
    d.setFontSize(dziecko && dziecko.length>12 ? 26 : 32);
    d.text(dziecko||'Nasze dziecko', W/2, 80, {align:'center'});
    d.setFont('Lato','normal'); d.setFontSize(12);
    if(rodzice) d.text(rodzice, W/2, 91, {align:'center'});
    if(termin){ d.setFontSize(10); d.text('Przewidywany termin: '+termin, W/2, 100, {align:'center'}); }
    d.setTextColor(t.ac[0],t.ac[1],t.ac[2]);
    d.setFont('Lato','bold'); d.setFontSize(13);
    d.text('PorodNaMiare.pl', W/2, H-42, {align:'center'});
    d.setTextColor(GREY[0],GREY[1],GREY[2]);
    d.setFont('Lato','normal'); d.setFontSize(8);
    d.text('Zgodny ze Standardem Opieki Okołoporodowej — Dz.U. 2025 poz. 1525', W/2, H-33, {align:'center'});
    d.setFontSize(7.5);
    d.text('Dokument organizacyjny — nie zastępuje porady lekarskiej.', W/2, H-27, {align:'center'});
  }

  function chrome(c){
    var d=c.d, t=c.t;
    d.setFillColor(t.ac[0],t.ac[1],t.ac[2]); d.rect(0,0,W,13,'F');
    d.setTextColor(255,255,255); d.setFont('Lato','bold'); d.setFontSize(9);
    d.text('PLAN PORODU', 16, 8.6);
    d.setFont('Lato','normal'); d.setFontSize(8);
    d.text('PorodNaMiare.pl', W-16, 8.6, {align:'right'});
    d.setFillColor(DEEP[0],DEEP[1],DEEP[2]); d.rect(0,H-9,W,9,'F');
    heart(d, 16, H-6, 1.5, [255,255,255]);
    d.setTextColor(255,255,255); d.setFontSize(7);
    d.text('Wygenerowano w PorodNaMiare.pl', 20, H-5.4);
    d.text('str. '+c.page, W-16, H-5.4, {align:'right'});
  }

  function newPage(c){
    if(c.page>0) c.d.addPage();
    c.page++;
    c.d.setFillColor(SAND[0],SAND[1],SAND[2]); c.d.rect(0,0,W,H,'F');
    chrome(c); c.y=22;
  }
  function need(c,h){ if(c.y+h > H-16) newPage(c); }

  function dataBox(c, rows){
    if(!rows.length) return;
    var d=c.d, t=c.t, bh=rows.length*7+7;
    need(c,bh+6);
    d.setFillColor(255,255,255); d.setDrawColor(SD[0],SD[1],SD[2]); d.setLineWidth(0.4);
    d.roundedRect(16,c.y,W-32,bh,3,3,'FD');
    d.setFillColor(t.ac[0],t.ac[1],t.ac[2]); d.roundedRect(16,c.y,2.5,bh,1,1,'F');
    var yy=c.y+8;
    rows.forEach(function(r){
      d.setTextColor(GREY[0],GREY[1],GREY[2]); d.setFont('Lato','normal'); d.setFontSize(7.5);
      d.text(String(r[0]).toUpperCase(), 23, yy);
      d.setTextColor(INK[0],INK[1],INK[2]); d.setFont('Lato','bold'); d.setFontSize(9.5);
      d.text(d.splitTextToSize(String(r[1]), W-96)[0], 72, yy);
      yy+=7;
    });
    c.y+=bh+6;
  }

  function priority(c){
    var d=c.d, t=c.t;
    var txt='PRIORYTET NADRZĘDNY: zdrowie i życie dziecka oraz matki są bezwzględnym priorytetem, nadrzędnym wobec każdego punktu tego planu. W sytuacji zagrożenia akceptujemy wszystkie niezbędne interwencje medyczne. Prosimy jedynie o możliwie szybką informację o sytuacji.';
    d.setFont('Lato','bold'); d.setFontSize(8.5);
    var lines=d.splitTextToSize(txt, W-48), bh=lines.length*4.4+8;
    need(c,bh+5);
    d.setFillColor(t.soft[0],t.soft[1],t.soft[2]); d.setDrawColor(t.ac[0],t.ac[1],t.ac[2]); d.setLineWidth(0.8);
    d.roundedRect(16,c.y,W-32,bh,3,3,'FD');
    d.setTextColor(DEEP[0],DEEP[1],DEEP[2]);
    var yy=c.y+6.5;
    lines.forEach(function(l){ d.text(l,22,yy); yy+=4.4; });
    c.y+=bh+6;
  }

  function section(c, num, title, items){
    if(!items || !items.length) return;
    var d=c.d, t=c.t;
    need(c,20);
    d.setFillColor(DEEP[0],DEEP[1],DEEP[2]); d.roundedRect(16,c.y,W-32,8.5,2.5,2.5,'F');
    d.setFillColor(t.ac[0],t.ac[1],t.ac[2]); d.circle(22.5,c.y+4.25,3.1,'F');
    d.setTextColor(255,255,255); d.setFont('Lato','bold'); d.setFontSize(8.5);
    d.text(String(num), 22.5, c.y+5.6, {align:'center'});
    d.setFontSize(10.5);
    d.text(d.splitTextToSize(title, W-70)[0], 29, c.y+5.7);
    c.y+=13;
    items.forEach(function(it){
      d.setFont('Lato','normal'); d.setFontSize(9.5);
      var lines=d.splitTextToSize(it, W-50);
      var rh=Math.max(6.8, lines.length*4.5+2.4);
      need(c,rh);
      d.setDrawColor(t.ac[0],t.ac[1],t.ac[2]); d.setFillColor(255,255,255); d.setLineWidth(0.5);
      d.roundedRect(20,c.y-0.4,3.6,3.6,0.7,0.7,'FD');
      d.setLineWidth(0.9);
      d.line(20.8,c.y+1.4,21.7,c.y+2.5); d.line(21.7,c.y+2.5,23,c.y+0.2);
      d.setTextColor(INK[0],INK[1],INK[2]);
      var yy=c.y+2.6;
      lines.forEach(function(l){ d.text(l,26,yy); yy+=4.5; });
      c.y+=rh;
    });
    c.y+=3;
  }

  function infoBox(c, title, txt){
    var d=c.d, t=c.t;
    d.setFont('Lato','normal'); d.setFontSize(8.5);
    var lines=d.splitTextToSize(txt, W-48), bh=lines.length*4.2+11;
    need(c,bh+5);
    d.setFillColor(255,255,255); d.setDrawColor(t.ac[0],t.ac[1],t.ac[2]); d.setLineWidth(0.5);
    d.roundedRect(16,c.y,W-32,bh,3,3,'FD');
    heart(d,22,c.y+5,2,t.ac);
    d.setTextColor(DEEP[0],DEEP[1],DEEP[2]); d.setFont('Lato','bold'); d.setFontSize(9);
    d.text(title,26,c.y+7);
    d.setTextColor(INK[0],INK[1],INK[2]); d.setFont('Lato','normal'); d.setFontSize(8.5);
    var yy=c.y+12;
    lines.forEach(function(l){ d.text(l,22,yy); yy+=4.2; });
    c.y+=bh+6;
  }

  function signatures(c){
    var d=c.d;
    need(c,52);
    d.setTextColor(DEEP[0],DEEP[1],DEEP[2]); d.setFont('Lato','bold'); d.setFontSize(11);
    d.text('Oświadczenie i podpisy',16,c.y); c.y+=7;
    d.setFont('Lato','normal'); d.setFontSize(9); d.setTextColor(INK[0],INK[1],INK[2]);
    d.splitTextToSize('Świadomie wyrażamy powyższe preferencje. Akceptujemy wszelkie niezbędne interwencje ratujące zdrowie i życie dziecka oraz matki.', W-32)
      .forEach(function(l){ d.text(l,16,c.y); c.y+=4.6; });
    c.y+=13;
    d.setDrawColor(SD[0],SD[1],SD[2]); d.setLineWidth(0.4);
    d.line(24,c.y,88,c.y); d.line(118,c.y,182,c.y);
    c.y+=5;
    d.setTextColor(GREY[0],GREY[1],GREY[2]); d.setFontSize(8);
    d.text('Matka',56,c.y,{align:'center'});
    d.text('Ojciec / osoba towarzysząca',150,c.y,{align:'center'});
    c.y+=10;
    d.setTextColor(INK[0],INK[1],INK[2]); d.setFontSize(9);
    d.text('Data: ............................................',16,c.y);
  }

  window.PNM_buildPlanPDF = function(data){
    var c=Doc(data.gender);
    cover(c, data.dziecko, data.rodzice, data.termin);
    newPage(c);
    dataBox(c, data.rows||[]);
    priority(c);
    var n=1;
    (data.sections||[]).forEach(function(s){
      if(s.items && s.items.length){
        section(c, n++, s.title, s.items);
        if(s.info) infoBox(c, s.info[0], s.info[1]);
      }
    });
    signatures(c);
    return c.d;
  };
})();
